const path = require('path');
const VModule = require('vmodule-webpack-plugin');
const pkg = require('./package.json');

function baseUrl() {
  const publicPath = process.env.DN_CMD == 'build' ?
    `//g.alicdn.com/aliyun/${pkg.name}/${pkg.version}/` : '/';
  return JSON.stringify(publicPath);
}

module.exports = function (conf, webpack) {
  Object.assign(conf.output, {
    globalObject: 'self',
  });
  conf.plugins.push(
    new webpack.IgnorePlugin(/^((fs)|(path)|(os)|(crypto)|(source-map-support))$/, /vs(\/|\\)language(\/|\\)typescript(\/|\\)lib/),
    new VModule({
      name: '$baseUrl',
      content: baseUrl()
    })
  );
};